import json

# Check the line items for CollabDesign Studio
line_items = locals().get('var_functions.query_db:8', [])
products = locals().get('var_functions.query_db:22', [])
product_dict = {p['Id']: p['Name'].strip() for p in products}

collab_item = None
for item in line_items:
    product_id = item.get('Product2Id', '')
    if product_id.startswith('#'):
        product_id = product_id[1:]
    if product_id in product_dict and 'CollabDesign' in product_dict[product_id]:
        collab_item = item
        break

result = {
    "collab_design_studio_item": collab_item,
    "violates_policy": collab_item is not None and float(collab_item.get('Quantity', 0)) > 25
}

print('__RESULT__:')
print(json.dumps(result))

